// Path resolution examples:
//
// Starting in: /var/www/uploads/
//
// ./photo.jpg        -> /var/www/uploads/photo.jpg     (stay here)
// ../config.txt      -> /var/www/config.txt            (up one)
// ../../secret.key   -> /var/secret.key                (up two)
// ../../../etc/passwd -> /etc/passwd                    (up three = root!)
//
// Java code to see this:
import java.io.File;

public class PathDemo {
    public static void main(String[] args) throws Exception {
        File base = new File("/var/www/uploads/");
        File safe = new File(base, "photo.jpg");
        File attack = new File(base, "../../../etc/passwd");

        System.out.println("Safe path:   " + safe.getPath());
        System.out.println("Safe canon:  " + safe.getCanonicalPath());
        System.out.println("Attack path: " + attack.getPath());
        System.out.println("Attack canon:" + attack.getCanonicalPath());
    }
}
// Output:
// Safe path:   /var/www/uploads/photo.jpg
// Safe canon:  /var/www/uploads/photo.jpg
// Attack path: /var/www/uploads/../../../etc/passwd
// Attack canon:/etc/passwd    <-- OUTSIDE uploads!

// VULNERABLE Java Servlet:
import javax.servlet.http.*;
import java.io.*;

public class FileServlet extends HttpServlet {
    private static final String BASE_DIR = "/var/www/uploads/";

    protected void doGet(HttpServletRequest req, HttpServletResponse resp)
            throws IOException {
        String filename = req.getParameter("file");
        // VULNERABLE: directly concatenating user input!
        File file = new File(BASE_DIR + filename);

        // Serve the file
        FileInputStream fis = new FileInputStream(file);
        byte[] buffer = new byte[1024];
        int bytesRead;
        while ((bytesRead = fis.read(buffer)) != -1) {
            resp.getOutputStream().write(buffer, 0, bytesRead);
        }
        fis.close();
    }
}

// Normal use:
// GET /files?file=photo.jpg
// Serves: /var/www/uploads/photo.jpg  ✅

// ATTACK:
// GET /files?file=../../../etc/passwd
// Serves: /var/www/uploads/../../../etc/passwd = /etc/passwd  💀

// WEAK FILTER (easily bypassed):
String filename = request.getParameter("file");
filename = filename.replace("../", ""); // Remove ../ sequences
File file = new File(BASE_DIR + filename);

// Bypass 1: Double dot-dot-slash
// Input: ....//....//....//etc/passwd
// After filter: ../../../etc/passwd (the inner ../ was removed, leaving outer ../)

// Bypass 2: URL encoding
// Input: %2e%2e%2fetc/passwd
// Filter checks for "../" but the input is "%2e%2e%2f" — doesn't match!
// Web server decodes AFTER the filter runs

// Bypass 3: Backslash (Windows)
// Input: ..\..\..\windows\win.ini
// Filter only removes "../" not "..\\" !

// Bypass 4: Nested removal
// Input: ..././..././..././etc/passwd
// Filter removes ../ from middle: ../../../etc/passwd

// CORRECT APPROACH: Canonical path (see next concept)

// Whitelist validation:
String filename = request.getParameter("file");

// Only allow alphanumeric, dot, underscore, hyphen
if (!filename.matches("[a-zA-Z0-9._-]+")) {
    throw new SecurityException(filename + " contains invalid characters");
}

File file = new File(BASE_DIR, filename);
// Now safe: filename cannot contain / or \ or ..

// Test cases:
// "photo.jpg"           -> PASS  (safe characters)
// "report_2024.pdf"     -> PASS  (safe characters)
// "../../../etc/passwd" -> FAIL  (contains / )
// "%2e%2e%2f"           -> FAIL  (contains % )
// "..\\etc\\passwd"   -> FAIL  (contains \\ )

// CORRECT canonical path validation:
String filename = request.getParameter("file");
final String BASE = "/var/www/uploads/"; // MUST end with /

File baseDir = new File(BASE);
File requestedFile = new File(baseDir, filename);

String canonicalPath = requestedFile.getCanonicalPath();
String canonicalBase = baseDir.getCanonicalPath();

// Check 1: Path must start with base directory
if (!canonicalPath.startsWith(canonicalBase)) {
    throw new SecurityException("Path traversal detected: " + filename);
}

// Check 2: Path must be LONGER than base (not the directory itself)
if (canonicalPath.length() <= canonicalBase.length() + 1) {
    throw new SecurityException("Invalid path: " + filename);
}

// Now safe to use the file
FileInputStream fis = new FileInputStream(requestedFile.getCanonicalFile());

// Trace:
// Input: ../../../etc/passwd
// Built: /var/www/uploads/../../../etc/passwd
// Canonical: /etc/passwd
// startsWith("/var/www/uploads")? NO -> BLOCKED!

import java.nio.file.*;

public class SecureFileAccess {
    private static final Path BASE = Paths.get("/var/www/uploads").toAbsolutePath();

    public static Path validatePath(String userInput) throws Exception {
        // Build path from user input
        Path requested = BASE.resolve(userInput).normalize();

        // Check it is within the base directory
        // Path.startsWith() compares COMPONENTS, not strings!
        if (!requested.startsWith(BASE)) {
            throw new SecurityException("Path traversal blocked: " + userInput);
        }

        // For existing files, also resolve symlinks:
        Path realPath = requested.toRealPath();
        if (!realPath.startsWith(BASE.toRealPath())) {
            throw new SecurityException("Symlink escape blocked: " + userInput);
        }

        return realPath;
    }
}

// Path.startsWith() is SAFER than String.startsWith():
// Paths.get("/safedirEVIL").startsWith(Paths.get("/safedir"))  -> FALSE ✅
// "/safedirEVIL".startsWith("/safedir")                       -> TRUE  ❌

// VULNERABLE ZIP extraction:
import java.util.zip.*;
import java.io.*;

public void extractZip(String zipPath, String destDir) throws Exception {
    ZipInputStream zis = new ZipInputStream(new FileInputStream(zipPath));
    ZipEntry entry;
    while ((entry = zis.getNextEntry()) != null) {
        // VULNERABLE: entry.getName() could be "../../../tmp/evil.sh"
        File outFile = new File(destDir, entry.getName());
        // Writes to /tmp/evil.sh instead of destDir!
        FileOutputStream fos = new FileOutputStream(outFile);
        // ... copy data ...
    }
}

// SECURE ZIP extraction:
public void extractZipSecure(String zipPath, String destDir) throws Exception {
    File dest = new File(destDir);
    ZipInputStream zis = new ZipInputStream(new FileInputStream(zipPath));
    ZipEntry entry;
    while ((entry = zis.getNextEntry()) != null) {
        File outFile = new File(dest, entry.getName());
        // Validate: canonical path must be inside destination!
        String canonicalDest = dest.getCanonicalPath() + File.separator;
        String canonicalOut = outFile.getCanonicalPath();
        if (!canonicalOut.startsWith(canonicalDest)) {
            throw new SecurityException("Zip Slip detected: " + entry.getName());
        }
        FileOutputStream fos = new FileOutputStream(outFile);
        // ... copy data ...
    }
}

