// SECURITY THROUGH OBSCURITY (BAD):
// "We renamed /etc/passwd to /etc/p4ssw0rd, nobody will find it!"
// Attacker: reads your deployment script, finds the real name

// OPEN DESIGN (GOOD):
// The validation works even if the attacker reads the source code:
public boolean isPathSafe(String filename, String baseDir) {
    // This code can be made completely public.
    // Even knowing the algorithm, attacker cannot bypass it.
    File base = new File(baseDir);
    File requested = new File(base, filename);
    try {
        return requested.getCanonicalPath().startsWith(
            base.getCanonicalPath() + File.separator);
    } catch (IOException e) {
        return false; // Fail safe!
    }
}

// Application of Least Privilege:

// BAD: Web server runs as root
// sudo java -jar webapp.jar
// If path traversal exists: attacker can read ANY file on the system!
// /etc/shadow, /root/.ssh/id_rsa, /etc/sudoers...

// GOOD: Web server runs as limited user 'webapp'
// su webapp -c 'java -jar webapp.jar'
// File permissions:
// /var/www/uploads/  -> readable by webapp
// /var/www/config/   -> readable by webapp
// /etc/passwd        -> readable (but limited info)
// /etc/shadow        -> NOT readable by webapp!
// /root/             -> NOT readable by webapp!

// Even with path traversal, damage is LIMITED
// The OS enforces what the app process can access

// Java security manager (additional layer):
// System.setSecurityManager(new SecurityManager());
// grant codeBase "file:/var/www/webapp.jar" {
//     permission java.io.FilePermission "/var/www/uploads/*", "read";
// };

// Defence in depth with multiple checks:
public File secureFileAccess(String filename) throws SecurityException {
    // CHECK 1: Whitelist validation
    if (!filename.matches("[a-zA-Z0-9._-]+")) {
        throw new SecurityException("Invalid characters in filename");
    }

    // CHECK 2: Canonical path validation
    File base = new File(BASE_DIR);
    File requested = new File(base, filename);
    try {
        String canonical = requested.getCanonicalPath();
        if (!canonical.startsWith(base.getCanonicalPath() + File.separator)) {
            throw new SecurityException("Path traversal detected");
        }
    } catch (IOException e) {
        throw new SecurityException("Path validation failed");
    }

    // CHECK 3: File exists and is readable
    if (!requested.exists() || !requested.canRead()) {
        throw new SecurityException("File not accessible");
    }

    // CHECK 4: File size limit (prevent serving huge files)
    if (requested.length() > 10_000_000) { // 10MB max
        throw new SecurityException("File too large");
    }

    return requested;
}

// Apache CVE-2021-41773 simplified:
// URL: http://server/icons/%2e%2e/%2e%2e/etc/passwd
// The %2e is URL-encoded dot (.)
// Apache decoded it to ../../etc/passwd
// But the path check ran BEFORE URL decoding!
// Check saw: /icons/%2e%2e/%2e%2e/etc/passwd (no ../ found)
// File system saw: /icons/../../etc/passwd = /etc/passwd
// Result: attacker reads /etc/passwd!

// Lesson: ALWAYS decode input BEFORE checking it
// Or better: check the CANONICAL path after resolution

public class PathTraversalLessons {
    public static void main(String[] args) {
        System.out.println("CVE-2021-41773: Apache path traversal");
        System.out.println("  Root cause: URL decoding after path check");
        System.out.println("  Impact: Any file readable by Apache user");
        System.out.println("  Fix: Canonical path validation");
        System.out.println();
        System.out.println("CVE-2018-13379: Fortinet VPN");
        System.out.println("  Root cause: No path validation on SSL VPN portal");
        System.out.println("  Impact: VPN credentials stolen");
        System.out.println("  Fix: Input validation + canonical path check");
    }
}

