// BAD: Caching validation (violates Complete Mediation)
import java.util.*;

public class CachedFileServer {
    private Set<String> validatedFiles = new HashSet<>();

    public void serve(String filename) {
        if (validatedFiles.contains(filename)) {
            // Already validated once - skip check!
            // DANGEROUS: what if a symlink was created since last check?
            doServe(filename);
        } else if (isPathSafe(filename)) {
            validatedFiles.add(filename);
            doServe(filename);
        } else {
            deny();
        }
    }
}
// Attack scenario:
