// 2. Attacker creates symlink: photo.jpg -> /etc/passwd
// 3. Request photo.jpg -> CACHED! Skips validation!
// 4. Serves /etc/passwd through the symlink!

// CORRECT: Validate EVERY time
public class SecureFileServer {
    public void serve(String filename) {
        // NO caching - validate on every request
        if (isPathSafe(filename)) {
            doServe(filename);
        } else {
            deny();
        }
    }
}

