import java.util.logging.*;

public class PrincipledFileServer {
    private static final Logger log = Logger.getLogger("Security");
    private final Path baseDir;

    public PrincipledFileServer(String baseDirPath) throws IOException {
        this.baseDir = Paths.get(baseDirPath).toRealPath();
    }

    public byte[] serveFile(String filename) throws SecurityException {
        // P1: Economy of Mechanism - simple whitelist
        if (!filename.matches("[a-zA-Z0-9._-]+")) {
            log.warning("Invalid chars in: " + filename);
            throw new SecurityException("Invalid filename");
        }

        // P3: Complete Mediation - validate EVERY request
        Path requested = baseDir.resolve(filename);

        // P5: Separation of Privilege - multiple checks
        try {
            Path real = requested.toRealPath();
            if (!real.startsWith(baseDir)) {
                log.severe("Path traversal: " + filename + " -> " + real);
                throw new SecurityException("Access denied");
            }

            // P6: Least Privilege - only read, size limit
            if (Files.size(real) > 10_000_000) {
                throw new SecurityException("File too large");
            }

            // P2: Fail-Safe - only serve if ALL checks pass
            return Files.readAllBytes(real);

        } catch (IOException e) {
            // P2: Fail-Safe - error = deny
            log.warning("File error for: " + filename);
            throw new SecurityException("File not accessible");
        }
    }
    // P4: Open Design - this code works even if attacker reads it
    // P7: Least Common Mechanism - file server is isolated
    // P8: Psychological Acceptability - users just provide filename
}

import java.nio.file.*;

public class SafeExecutor {
    private static final Path SAFE_DIR = Paths.get("safe_programs").toAbsolutePath();

    // VULNERABLE version:
    public static int executeVulnerable(String programName) throws Exception {
        Path program = SAFE_DIR.resolve(programName);
        // No validation! Attacker sends: ../unsafe_program
        Process p = Runtime.getRuntime().exec(program.toString());
        return p.waitFor();
    }

    // First attempt (weak):
    public static int executeWeak(String programName) throws Exception {
        // Only checks for File.separator
        if (programName.contains(java.io.File.separator)) {
            throw new SecurityException("Path separator detected");
        }
        // On Windows, File.separator is \\ but / also works!
        // Attacker sends: ../unsafe_program (uses / not \\)
        Path program = SAFE_DIR.resolve(programName);
        Process p = Runtime.getRuntime().exec(program.toString());
        return p.waitFor();
    }

    // SECURE version:
    public static int executeSecure(String programName) throws Exception {
        // Whitelist: only alphanumeric and underscore
        if (!programName.matches("[a-zA-Z0-9_]+")) {
            throw new SecurityException("Invalid program name");
        }

        Path program = SAFE_DIR.resolve(programName).toRealPath();

        // Verify parent is exactly the safe directory
        if (!program.getParent().equals(SAFE_DIR.toRealPath())) {
            throw new SecurityException("Path traversal detected");
        }

        Process p = Runtime.getRuntime().exec(program.toString());
        return p.waitFor();
    }
}

public class CVE_2021_41773_Analysis {
    public static void main(String[] args) {
        System.out.println("=== CVE-2021-41773: Apache HTTP Server ===");
        System.out.println("Severity: CRITICAL (CVSS 9.8)");
        System.out.println("Affected: Apache 2.4.49");
        System.out.println();

        System.out.println("ROOT CAUSE:");
        System.out.println("Apache's path normalization ran BEFORE URL decoding.");
        System.out.println("The normalization checked for ../ (literal characters).");
        System.out.println("But %2e was NOT decoded yet, so %2e%2e/ passed the check.");
        System.out.println("After the check, the URL was decoded: %2e%2e/ became ../");
        System.out.println("The file system then resolved ../ and escaped the web root!");
        System.out.println();

        System.out.println("ATTACK:");
        System.out.println("curl http://target/icons/%2e%2e/%2e%2e/etc/passwd");
        System.out.println("  Step 1: Apache receives /icons/%2e%2e/%2e%2e/etc/passwd");
        System.out.println("  Step 2: Normalization looks for ../ -> NOT found (%2e%2e)");
        System.out.println("  Step 3: URL decode -> /icons/../../etc/passwd");
        System.out.println("  Step 4: File system resolves -> /etc/passwd");
        System.out.println("  Step 5: Apache serves /etc/passwd!");
        System.out.println();

        System.out.println("LESSON:");
        System.out.println("Always decode ALL input BEFORE running security checks.");
        System.out.println("Or better: validate the CANONICAL path after resolution.");
        System.out.println("Order matters: decode -> normalize -> validate -> serve");
    }
}

